import{_ as e,c as r,o as t,aj as l,ak as i,al as o,am as n,an as s,ao as h}from"./chunks/framework.DzoSnc92.js";const k=JSON.parse('{"title":"第一章 计算机系统概论","description":"","frontmatter":{},"headers":[],"relativePath":"Computer-Organization-and-Architecture/src/chap01.md","filePath":"Computer-Organization-and-Architecture/src/chap01.md"}'),c={name:"Computer-Organization-and-Architecture/src/chap01.md"};function d(p,a,b,g,m,_){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="第一章-计算机系统概论" tabindex="-1">第一章 计算机系统概论 <a class="header-anchor" href="#第一章-计算机系统概论" aria-label="Permalink to “第一章 计算机系统概论”">​</a></h1><p>概括介绍整个计算机系统的组成和工作原理。</p><h2 id="_1-1-计算机系统简介" tabindex="-1">1.1 计算机系统简介 <a class="header-anchor" href="#_1-1-计算机系统简介" aria-label="Permalink to “1.1 计算机系统简介”">​</a></h2><h3 id="_1-1-1-计算机的软硬件概念" tabindex="-1">1.1.1 计算机的软硬件概念 <a class="header-anchor" href="#_1-1-1-计算机的软硬件概念" aria-label="Permalink to “1.1.1 计算机的软硬件概念”">​</a></h3><p>计算机由<code>软件</code>和<code>硬件</code>两部分组成。</p><blockquote><p><strong>硬件</strong>(Hardware)：指计算机系统中<code>物理</code>存在的各种<code>设备</code>，如CPU、内存、硬盘、显示器、键盘、鼠标等。</p><blockquote><p>硬件的分类：</p><ul><li>输入设备：如键盘、鼠标、扫描仪等。</li><li>输出设备：如显示器、打印机、音响等。</li><li>存储设备：如硬盘、内存等。</li><li>处理设备：如CPU、显卡等。</li></ul></blockquote></blockquote><hr><blockquote><p><strong>软件</strong>(Software)：指计算机系统中<code>非物理</code>存在的各种<code>程序</code>，如操作系统、应用程序、数据库管理系统等。</p><blockquote><p>软件的分类：</p><ul><li>系统软件：如操作系统、编译器、解释器等。</li><li>应用软件：如文字处理软件、数据库管理软件、图形处理软件等。</li></ul></blockquote></blockquote><h3 id="_1-1-2-计算机系统的层次结构" tabindex="-1">1.1.2 计算机系统的层次结构 <a class="header-anchor" href="#_1-1-2-计算机系统的层次结构" aria-label="Permalink to “1.1.2 计算机系统的层次结构”">​</a></h3><p>当代计算机在运行一段代码或者应用程序时，会经历以下几个层次的处理：</p><blockquote><p>本课程只讨论传统机器M1 和微程序机器M0的组成原理及设计思想，</p></blockquote><h2 id="alt-text" tabindex="-1"><img src="'+i+'" alt="alt text"> <a class="header-anchor" href="#alt-text" aria-label="Permalink to “”">​</a></h2><h2 id="_1-2-计算机的基本组成" tabindex="-1">1.2 计算机的基本组成 <a class="header-anchor" href="#_1-2-计算机的基本组成" aria-label="Permalink to “1.2 计算机的基本组成”">​</a></h2><h3 id="_1-2-1-冯·诺依曼结构与现代计算机结构" tabindex="-1">1.2.1 冯·诺依曼结构与现代计算机结构 <a class="header-anchor" href="#_1-2-1-冯·诺依曼结构与现代计算机结构" aria-label="Permalink to “1.2.1 冯·诺依曼结构与现代计算机结构”">​</a></h3><p>1945年，美国数学家冯·诺依曼（von Neumann）提出了一种基于<code>存储程序</code>概念的计算机结构，被称为<code>冯·诺依曼结构</code>。</p><p>这个结构的奠定了现代计算机的基础。</p><h4 id="冯·诺依曼结构图" tabindex="-1">冯·诺依曼结构图 <a class="header-anchor" href="#冯·诺依曼结构图" aria-label="Permalink to “冯·诺依曼结构图”">​</a></h4><h2 id="冯诺依曼结构" tabindex="-1"><img src="'+o+'" alt="冯诺依曼结构"> <a class="header-anchor" href="#冯诺依曼结构" aria-label="Permalink to “”">​</a></h2><p>图中各部件的功能如下：</p><ol><li><strong>运算器</strong>用来完成算术运算和逻辑运算，并将运算的中间结果暂存在运算器内。</li><li><strong>存储器</strong>用来存放数据和程序。</li><li><strong>控制器</strong>用来控制、指挥程序和数据的输入、运行以及处理运算结果。</li><li><strong>输入设备</strong>用来将人们熟悉的信息形式转换为机器能识别的信息形式，常见的有键盘、鼠标等。</li><li><strong>输出设备</strong>可将机器运算结果转换为人们熟悉的信息形式，如打印机输出、显示器输出等。</li></ol><hr><p>冯·诺依曼结构的主要特点包括：</p><ol><li>计算机由<strong>运算器、存储器、控制器、输入设备和输出设备</strong>五大部件组成。</li><li>指令和数据以同等地位存放在存储器内，并可按地址寻访。</li><li>指令和数据均用二进制数表示。</li><li><strong>指令由操作码和地址码组成</strong>，操作码用来表示操作的性质，地址码用来表示操作数在存储器中的位置。</li><li><strong>指令在存储器内按顺序存放</strong>。通常，指令是顺序执行的，在特定条件下，可根据运算结果或根据设定的条件改变执行顺序。</li><li><strong>机器以运算器为中心</strong>，输入输出设备与存储器间的数据传送通过运算器完成。</li></ol><hr><p>随着技术发展，现代的计算机已转化为以存储器为中心，而不是以运算器为中心。</p><h4 id="现代计算机五大部件结构图" tabindex="-1">现代计算机五大部件结构图 <a class="header-anchor" href="#现代计算机五大部件结构图" aria-label="Permalink to “现代计算机五大部件结构图”">​</a></h4><h2 id="现代计算机结构图" tabindex="-1"><img src="'+n+'" alt="现代计算机结构图"> <a class="header-anchor" href="#现代计算机结构图" aria-label="Permalink to “”">​</a></h2><p>计算机的五大部件在控制器的统一指挥下，有条不紊地自动工作。</p><p>运算器和控制器在逻辑关系和电路结构上联系十分紧密，尤其在大规模集成电路制作工艺出现后，这两大部件往往集成在同一芯片上，也就是<strong>中央处理器</strong>（<strong>CPU</strong>）。 输入设备与输出设备简称为 <strong>I/0</strong> 设备</p><p>因此，现代计算机的结构可以总结为3部分：</p><ol><li><strong>CPU</strong></li><li><strong>内存（或称主存储器）</strong></li><li><strong>I/O设备</strong></li></ol><h4 id="现代计算机组成框图" tabindex="-1">现代计算机组成框图 <a class="header-anchor" href="#现代计算机组成框图" aria-label="Permalink to “现代计算机组成框图”">​</a></h4><h2 id="alt-text-1" tabindex="-1"><img src="'+s+'" alt="alt text"> <a class="header-anchor" href="#alt-text-1" aria-label="Permalink to “”">​</a></h2><p>运算器和控制器名称也有不同的叫法：</p><ol><li>算术逻辑单元(Arithmetic Logic Unit, ALU) 简称算逻部件，用来完成算术逻辑运算。</li><li>控制单元(Control Unit, CU) 用来解释存储器中的指令，并发出各种操作命令来执行指令。</li></ol><h3 id="_1-2-2-计算机硬件的主要技术指标" tabindex="-1">1.2.2 计算机硬件的主要技术指标 <a class="header-anchor" href="#_1-2-2-计算机硬件的主要技术指标" aria-label="Permalink to “1.2.2 计算机硬件的主要技术指标”">​</a></h3><h4 id="机器字长" tabindex="-1">机器字长 <a class="header-anchor" href="#机器字长" aria-label="Permalink to “机器字长”">​</a></h4><p>机器字长是指CPU一次能处理数据的位数，通常与 CPU 的寄存器位数有关。字长越长，数的表示范围越大，精度也越高。机器的字长也会影响机器的运算速度。倘若CPU字长较短，又要运算位数较多的数据，那么需要经过两次或多次的运算才能完成，这样势必影响机器的运算速度。 机器字长对硬件的造价也有较大的影响。它将直接影响加法器（或 ALU）、数据总线以及存储字长的位数。所以机器字长的确定不能单从精度和数的表示范围来考虑。</p><h4 id="存储容量" tabindex="-1">存储容量 <a class="header-anchor" href="#存储容量" aria-label="Permalink to “存储容量”">​</a></h4><p>存储容量是指存储器所能存储的二进制信息的总量。 通常用字节（Byte）为单位来表示。 1字节（Byte）= 8位（bit） 1位有0和1两种状态，那16位就是：$2^{16}$ ，即65536个状态。</p><p>现代计算机中常以字节Byte数来描述容量的大小，因一个字节已被定义为8位二进制代码，故用字节数便能反映主存容量。</p><p>假设，存储容量为 2M bit，即$2^{20}$，1024=1K，1024K=1M。 若将其转换为Byte，即：$2^{20}/8=2^{17}$，记作 $2^{17}$ B 、$2^{7}$ KB、 128 KB 。</p><h4 id="运算速度" tabindex="-1">运算速度 <a class="header-anchor" href="#运算速度" aria-label="Permalink to “运算速度”">​</a></h4><p>现在机器的运算速度普遍采用单位时间内执行指令的平均条数来衡量，并用 MIPS（百万条指令每秒）作为计量单位。例如，某机每秒能执行 200 万条指令，则记作2 MIPS。 或用 FLOPS（浮点运算次数每秒）来衡量运算速度。</p><h2 id="本课程涉及的主要模块alt-text" tabindex="-1">本课程涉及的主要模块 <img src="'+h+'" alt="alt text"> <a class="header-anchor" href="#本课程涉及的主要模块alt-text" aria-label="Permalink to “本课程涉及的主要模块”">​</a></h2>',45)])])}const x=e(c,[["render",d]]);export{k as __pageData,x as default};
